<!-- fits: the leading `line` before `ccccc` renders flat, as a space -->
<li>
	aaaaa ~{xxxxxxxxxx} bbbbb ~{yyyyyyyyyy} ccccc ccccc ccccc
</li>

<!-- breaks AT that leading `line`: it must become the newline, not a space after it -->
<li>
	aaaaa aaaaa aaaaa aaaaa aaaaa ~{xxxxxxxxxx} bbbbb bbbbb bbbbb bbbbb bbbbb bbbbb bbbbb
	~{yyyyyyyyyy}
	ccccc ccccc ccccc ccccc
</li>
